inline:<div id="header-root" class="c1-container">
  <style>
    #header-root {
      --glow-green: #39FF14;
      --glow-cyan: #00FFFF;
      background: #050A0C;
      padding: 3rem 2rem;
      display: flex;
      justify-content: center;
      align-items: center;
      border-bottom: 2px solid var(--glow-green);
      box-shadow: 0 0 20px rgba(57, 255, 20, 0.3);
      position: relative;
      overflow: hidden;
    }
    .c1-title {
      font-family: 'Inter', 'Montserrat', sans-serif;
      font-size: clamp(1.5rem, 5vw, 3rem);
      color: #fff;
      text-transform: uppercase;
      letter-spacing: 0.3em;
      text-align: center;
      z-index: 2;
      text-shadow: 0 0 10px var(--glow-cyan);
    }
    .c1-organic-line {
      position: absolute;
      width: 100%;
      height: 2px;
      background: linear-gradient(90deg, transparent, var(--glow-green), var(--glow-cyan), transparent);
      top: 50%;
      left: 0;
      opacity: 0.6;
      transition: opacity 0.5s ease;
    }
  </style>
  <div class="c1-organic-line" id="header-root-line"></div>
  <h1 class="c1-title">The DNA Archive: Digitalized Life</h1>
  <script>
    window.c1_updateHeaderGlow = (intensity) => {
      const line = document.getElementById('header-root-line');
      if(line) line.style.opacity = intensity || 0.6;
    };
    window.c1_mount = () => {
      const reduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
      if (!reduced) {
        const line = document.getElementById('header-root-line');
        let step = 0;
        const anim = () => {
          step += 0.05;
          line.style.transform = `translateX(${Math.sin(step)*10}px)`;
          window.c1_raf_id = requestAnimationFrame(anim);
        };
        anim();
      }
    };
    window.c1_destroy = () => {
      cancelAnimationFrame(window.c1_raf_id);
    };
  </script>
</div>
